-- ============================================================================
-- Minecraft Gilde sample data
--
-- Synthetic dataset with 20 players for local development and testing.
-- Covers all metric_source-referenced stats keys and all leaderboard tables.
-- Requires db/schema.sql to be applied first.
-- ============================================================================

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET time_zone = "+00:00";
SET NAMES utf8mb4;

START TRANSACTION;

SET @sample_run_id := 900001;

-- Clean up an earlier copy of this sample run if it already exists.
UPDATE `site_state`
SET `active_run_id` = NULL
WHERE `id` = 1 AND `active_run_id` = @sample_run_id;

DELETE FROM `metric_award` WHERE `run_id` = @sample_run_id;
DELETE FROM `metric_value` WHERE `run_id` = @sample_run_id;
DELETE FROM `player_stats` WHERE `run_id` = @sample_run_id;
DELETE FROM `player_profile` WHERE `run_id` = @sample_run_id;
DELETE FROM `import_run` WHERE `id` = @sample_run_id;

INSERT INTO `import_run` (`id`, `generated_at`, `status`, `note`) VALUES
(@sample_run_id, '2026-03-21 12:00:00', 'active', 'Synthetic sample dataset with 20 players');

INSERT INTO `site_state` (`id`, `active_run_id`) VALUES (1, @sample_run_id)
ON DUPLICATE KEY UPDATE `active_run_id` = VALUES(`active_run_id`);

CREATE TEMPORARY TABLE `sample_player` (
  `player_idx` TINYINT UNSIGNED NOT NULL,
  `uuid_bin` BINARY(16) NOT NULL,
  `name` VARCHAR(16) NOT NULL,
  `name_lc` VARCHAR(16) NOT NULL,
  `name_source` VARCHAR(16) NOT NULL,
  `name_checked_at` DATETIME DEFAULT NULL,
  `last_seen` DATETIME NOT NULL,
  `activity_base` INT NOT NULL,
  PRIMARY KEY (`player_idx`),
  UNIQUE KEY `uq_sample_uuid` (`uuid_bin`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

