-- Materialize metric values for every enabled metric except king.
WITH `ordered_metrics` AS (
  SELECT
    `id` AS `metric_id`,
    ROW_NUMBER() OVER (ORDER BY `sort_order` ASC, `id` ASC) AS `metric_idx`
  FROM `metric_def`
  WHERE `enabled` = 1 AND `id` <> 'king'
)
INSERT INTO `metric_value` (`run_id`, `metric_id`, `uuid`, `value`)
SELECT
  @sample_run_id,
  `om`.`metric_id`,
  `sp`.`uuid_bin`,
  (
    `sp`.`activity_base` + ((`sp`.`player_idx` * 11 + `om`.`metric_idx` * 7) % 19) +
    CASE
      WHEN MOD(`om`.`metric_idx`, 7) = 0 AND `sp`.`player_idx` IN (((`om`.`metric_idx` - 1) % 20) + 1, ((`om`.`metric_idx` + 5) % 20) + 1) THEN 180
      WHEN MOD(`om`.`metric_idx`, 11) = 0 AND `sp`.`player_idx` = (((`om`.`metric_idx` - 1) % 20) + 1) THEN 160
      WHEN MOD(`om`.`metric_idx`, 11) = 0 AND `sp`.`player_idx` IN (((`om`.`metric_idx` + 5) % 20) + 1, ((`om`.`metric_idx` + 11) % 20) + 1) THEN 120
      WHEN `sp`.`player_idx` = (((`om`.`metric_idx` - 1) % 20) + 1) THEN 200
      WHEN `sp`.`player_idx` = (((`om`.`metric_idx` + 5) % 20) + 1) THEN 130
      WHEN `sp`.`player_idx` = (((`om`.`metric_idx` + 11) % 20) + 1) THEN 70
      ELSE 0
    END
  ) * CASE
    WHEN `om`.`metric_id` IN ('aviate_one_cm', 'boat_one_cm', 'climb_one_cm', 'crouch_one_cm', 'distance', 'horse_one_cm', 'minecart_one_cm', 'sprint_one_cm', 'strider_one_cm', 'swim_one_cm') THEN 100000
    WHEN `om`.`metric_id` IN ('hours', 'time_since_death_h', 'time_since_rest_h') THEN 72000
    ELSE 1
  END AS `value`
FROM `sample_player` `sp`
CROSS JOIN `ordered_metrics` `om`;

-- Top-3 awards per metric, following the importer ranking rules.
WITH `ranked_metrics` AS (
  SELECT
    `metric_id`,
    `uuid`,
    `value`,
    ROW_NUMBER() OVER (PARTITION BY `metric_id` ORDER BY `value` DESC, `uuid` ASC) AS `place`
  FROM `metric_value`
  WHERE `run_id` = @sample_run_id AND `metric_id` <> 'king' AND `value` > 0
)
INSERT INTO `metric_award` (`run_id`, `metric_id`, `place`, `uuid`, `value`, `points`)
SELECT
  @sample_run_id,
  `metric_id`,
  `place`,
  `uuid`,
  `value`,
  CASE `place` WHEN 1 THEN 5 WHEN 2 THEN 3 WHEN 3 THEN 1 END AS `points`
FROM `ranked_metrics`
WHERE `place` <= 3;

-- Aggregate Server-K?nig points from the generated awards.
INSERT INTO `metric_value` (`run_id`, `metric_id`, `uuid`, `value`)
SELECT
  @sample_run_id,
  'king',
  `uuid`,
  SUM(`points`) AS `value`
FROM `metric_award`
WHERE `run_id` = @sample_run_id
GROUP BY `uuid`;

DROP TEMPORARY TABLE `sample_player`;

COMMIT;
